using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for Person: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false when metadata isn't available.
//    Use a resolver that resolves nothing to simulate "not available".
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty – resolves nothing
};

bool found = limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"TryGetTypeInfo on limited options: found={found}, info is null={info is null}");

// Contrast: the full resolver does find it.
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"TryGetTypeInfo on full options:    found={found2}, type={info2?.Type.Name}");

public record Person(string Name, int Age);

